import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  Container, Row, Col, Button, Card, Form, 
  Spinner, Alert, Badge, Modal, ButtonGroup
} from 'react-bootstrap';
import axios from 'axios';
import { formatDistanceToNow } from 'date-fns';
import { FaThumbsUp, FaThumbsDown, FaEdit, FaTrash } from 'react-icons/fa';

const Problem = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  
  // State management
  const [problem, setProblem] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [solution, setSolution] = useState('');
  const [solutions, setSolutions] = useState([]);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [solutionToDelete, setSolutionToDelete] = useState(null);
  const [editingSolutionId, setEditingSolutionId] = useState(null);
  const [editSolutionContent, setEditSolutionContent] = useState('');

  // Fetch problem and solutions
  useEffect(() => {
    const fetchProblemData = async () => {
      try {
        setLoading(true);
        const response = await axios.get(`/api/problems/${id}`);
        setProblem(response.data.problem);
        setSolutions(response.data.solutions);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch problem');
      } finally {
        setLoading(false);
      }
    };

    fetchProblemData();
  }, [id]);

  // Handle solution submission
  const handleSubmitSolution = async (e) => {
    e.preventDefault();
    try {
      const response = editingSolutionId 
        ? await axios.put(`/api/solutions/${editingSolutionId}`, { content: solution })
        : await axios.post(`/api/problems/${id}/solutions`, { content: solution });
      
      if (editingSolutionId) {
        setSolutions(solutions.map(sol => 
          sol._id === editingSolutionId ? response.data.solution : sol
        ));
        setEditingSolutionId(null);
      } else {
        setSolutions([...solutions, response.data.solution]);
      }
      setSolution('');
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to submit solution');
    }
  };

  // Handle solution voting
  const handleVote = async (solutionId, voteType) => {
    try {
      const response = await axios.post(`/api/solutions/${solutionId}/vote`, { voteType });
      setSolutions(solutions.map(sol => 
        sol._id === solutionId ? response.data.solution : sol
      ));
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to process vote');
    }
  };

  // Handle solution editing
  const handleEditSolution = (solution) => {
    setEditingSolutionId(solution._id);
    setSolution(solution.content);
  };

  // Handle solution deletion
  const handleDeleteSolution = async () => {
    try {
      await axios.delete(`/api/solutions/${solutionToDelete}`);
      setSolutions(solutions.filter(sol => sol._id !== solutionToDelete));
      setShowDeleteModal(false);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete solution');
    }
  };

  if (loading) return (
    <div className="d-flex justify-content-center mt-5">
      <Spinner animation="border" role="status">
        <span className="visually-hidden">Loading...</span>
      </Spinner>
    </div>
  );

  if (error) return (
    <Container className="mt-4">
      <Alert variant="danger">{error}</Alert>
      <Button onClick={() => navigate(-1)}>Back to Problems</Button>
    </Container>
  );

  return (
    <Container className="mt-4">
      {/* Problem Details Section */}
      <Button variant="outline-primary" onClick={() => navigate(-1)} className="mb-3">
        Back to Problems
      </Button>

      <Card className="mb-4 shadow-sm">
        <Card.Body>
          <div className="d-flex justify-content-between align-items-start">
            <div>
              <Card.Title className="mb-2">{problem.title}</Card.Title>
              <div className="mb-3">
                <Badge bg="info" className="me-2">{problem.category}</Badge>
                <Badge bg={problem.difficulty === 'easy' ? 'success' : 
                           problem.difficulty === 'medium' ? 'warning' : 'danger'}>
                  {problem.difficulty}
                </Badge>
              </div>
            </div>
            <small className="text-muted">
              Posted {formatDistanceToNow(new Date(problem.createdAt))} ago
            </small>
          </div>
          <Card.Text className="lead">{problem.description}</Card.Text>
        </Card.Body>
      </Card>

      {/* Solution Section */}
      <Row>
        {/* Submit/Edit Solution Form */}
        <Col md={6}>
          <Card className="mb-4 shadow-sm">
            <Card.Body>
              <Card.Title>
                {editingSolutionId ? 'Edit Your Solution' : 'Submit a Solution'}
              </Card.Title>
              <Form onSubmit={handleSubmitSolution}>
                <Form.Group className="mb-3">
                  <Form.Control
                    as="textarea"
                    rows={8}
                    value={solution}
                    onChange={(e) => setSolution(e.target.value)}
                    placeholder="Explain your solution step-by-step..."
                    required
                  />
                </Form.Group>
                <div className="d-flex justify-content-between">
                  <Button variant="primary" type="submit">
                    {editingSolutionId ? 'Update Solution' : 'Submit Solution'}
                  </Button>
                  {editingSolutionId && (
                    <Button 
                      variant="outline-secondary" 
                      onClick={() => {
                        setEditingSolutionId(null);
                        setSolution('');
                      }}
                    >
                      Cancel Edit
                    </Button>
                  )}
                </div>
              </Form>
            </Card.Body>
          </Card>
        </Col>

        {/* Existing Solutions */}
        <Col md={6}>
          <h4 className="mb-3">
            Solutions <Badge bg="primary" pill>{solutions.length}</Badge>
          </h4>
          
          {solutions.length === 0 ? (
            <Alert variant="info">
              No solutions yet. Be the first to solve this problem!
            </Alert>
          ) : (
            solutions.map((sol) => (
              <Card key={sol._id} className="mb-3 shadow-sm">
                <Card.Body>
                  <div className="d-flex justify-content-between mb-2">
                    <div>
                      <strong>{sol.author.name}</strong>
                      <small className="text-muted ms-2">
                        {formatDistanceToNow(new Date(sol.createdAt))} ago
                      </small>
                    </div>
                    {sol.isAuthor && (
                      <ButtonGroup size="sm">
                        <Button 
                          variant="outline-primary" 
                          size="sm"
                          onClick={() => handleEditSolution(sol)}
                        >
                          <FaEdit />
                        </Button>
                        <Button 
                          variant="outline-danger" 
                          size="sm"
                          onClick={() => {
                            setSolutionToDelete(sol._id);
                            setShowDeleteModal(true);
                          }}
                        >
                          <FaTrash />
                        </Button>
                      </ButtonGroup>
                    )}
                  </div>
                  <Card.Text className="mb-3">{sol.content}</Card.Text>
                  <div className="d-flex align-items-center">
                    <Button 
                      variant={sol.userVote === 'up' ? 'success' : 'outline-success'} 
                      size="sm" 
                      className="me-2"
                      onClick={() => handleVote(sol._id, 'up')}
                    >
                      <FaThumbsUp /> {sol.upvotes}
                    </Button>
                    <Button 
                      variant={sol.userVote === 'down' ? 'danger' : 'outline-danger'} 
                      size="sm"
                      onClick={() => handleVote(sol._id, 'down')}
                    >
                      <FaThumbsDown /> {sol.downvotes}
                    </Button>
                  </div>
                </Card.Body>
              </Card>
            ))
          )}
        </Col>
      </Row>

      {/* Delete Confirmation Modal */}
      <Modal show={showDeleteModal} onHide={() => setShowDeleteModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Confirm Deletion</Modal.Title>
        </Modal.Header>
        <Modal.Body>Are you sure you want to delete this solution?</Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>
            Cancel
          </Button>
          <Button variant="danger" onClick={handleDeleteSolution}>
            Delete
          </Button>
        </Modal.Footer>
      </Modal>
    </Container>
  );
};

export default Problem;
